#include <iostream>
#include <sstream>
#include <string>

std::string convertMarkdownToHtml(const std::string& markdownText) {
    std::stringstream ss;
    ss << "<html><body>" << markdownText << "</body></html>";
    return ss.str();
}

int main() {
    std::string markdownText = "This is a markdown text.";
    std::string htmlText = convertMarkdownToHtml(markdownText);
    std::cout << "HTML formatted text: " << htmlText << std::endl;
    return 0;
}
```

In this example, the `convertMarkdownToHtml` function takes a `const` reference to a `std::string` containing markdown formatted text. It creates a `std::stringstream` object `ss` and constructs the HTML formatted text by concatenating the markdown text into the `ss` object. Finally, it returns the result of the `ss` object.

In the `main` function, we create a `std::string` variable `markdownText` with a sample markdown text. Then, we pass the `markdownText` to the `convertMarkdownToHtml` function and assign the returned `std::string` to the `htmlText` variable. Finally, we print the HTML formatted text to the console.

