function checkPrime(numbers) {
  for (let i = 0; i < numbers.length; i++) {
    let number = numbers[i];
    if (number >= 2 && isPrime(number)) {
      console.log(number);
      break; // Stop the loop as we found a prime number
    }
  }
}

function isPrime(number) {
  if (number <= 1) {
    return false;
  }
  for (let i = 2; i <= Math.sqrt(number); i++) {
    if (number % i === 0) {
      return false;
    }
  }
  return true;
}
```

